package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Method;
import java.util.HashMap;
import java.util.Map;

public class CSVRecordTest {

    @Test
    void testGetCommentReturnsCorrectComment() {
        String[] values = new String[] {"value1", "value2"};
        Map<String, Integer> mapping = new HashMap<>();
        String comment = "This is a comment";
        long recordNumber = 123L;

        CSVRecord record = new CSVRecord(values, mapping, comment, recordNumber);
        assertEquals(comment, record.getComment());
    }

    @Test
    void testGetCommentReturnsNullWhenCommentIsNull() throws Exception {
        String[] values = new String[] {"value1"};
        Map<String, Integer> mapping = new HashMap<>();
        long recordNumber = 1L;

        // Use reflection to create CSVRecord with null comment because constructor is package-private
        CSVRecord record = createCSVRecordWithNullComment(values, mapping, recordNumber);
        assertNull(record.getComment());
    }

    // Helper method to create CSVRecord instance with null comment using reflection
    private CSVRecord createCSVRecordWithNullComment(String[] values, Map<String, Integer> mapping, long recordNumber) throws Exception {
        Class<CSVRecord> clazz = CSVRecord.class;
        var constructor = clazz.getDeclaredConstructor(String[].class, Map.class, String.class, long.class);
        constructor.setAccessible(true);
        return constructor.newInstance(values, mapping, null, recordNumber);
    }
}
